mapper.select:
SELECT DISTINCT ON (COALESCE(relname, ''), COALESCE(database_name, '')) *
FROM memory_raw
WHERE instance_id = #{instanceId}
  AND collected_at < #{currentCollectedAt}
ORDER BY COALESCE(relname, ''), COALESCE(database_name, ''), collected_at DESC

WITH cache_hit_aggregated AS ( SELECT NULL as relname, database_name, ROUND(AVG(cache_hit_ratio)::numeric, 2) as cache_hit_ratio, COALESCE(SUM(delta_heap_blks_read + delta_idx_blks_read), 0) as physical_reads, COALESCE(SUM(delta_heap_blks_hit + delta_idx_blks_hit), 0) as cache_hits, CASE WHEN AVG(cache_hit_ratio) < 85 THEN '위험' WHEN AVG(cache_hit_ratio) < 95 THEN '주의' ELSE '정상' END as status FROM memory_agg_1m WHERE instance_id = #{instanceId} AND collected_at >= #{startTime} AND collected_at <= #{endTime} AND relname IS NULL AND database_name IS NOT NULL GROUP BY database_name ), ranked_data AS ( SELECT ROW_NUMBER() OVER (ORDER BY cache_hit_ratio ASC) as rank_num, relname, database_name, cache_hit_ratio, physical_reads, cache_hits, status FROM cache_hit_aggregated WHERE 1=1
AND status IN
#{statusItem}
) SELECT rank_num, relname, database_name, cache_hit_ratio, physical_reads, cache_hits, status FROM ranked_data ORDER BY cache_hit_ratio ASC LIMIT #{limit} OFFSET #{offset}

WITH cache_hit_aggregated AS ( SELECT NULL as relname, database_name, CASE WHEN AVG(cache_hit_ratio) < 85 THEN '위험' WHEN AVG(cache_hit_ratio) < 95 THEN '주의' ELSE '정상' END as status FROM memory_agg_1m WHERE instance_id = #{instanceId} AND collected_at >= #{startTime} AND collected_at <= #{endTime} AND relname IS NULL AND database_name IS NOT NULL GROUP BY database_name ) SELECT COUNT(*) FROM cache_hit_aggregated WHERE 1=1
AND status IN
#{statusItem}

SELECT
    TO_CHAR(collected_at, 'HH24:MI') as time_label,
    COALESCE(ROUND(AVG(buffer_hit_ratio)::numeric, 2), 0) as cache_hit_ratio
FROM disk_io_agg_1m
WHERE instance_id = #{instanceId}
  AND collected_at >= #{startTime} AND collected_at  <=  #{endTime}
  AND database_name IS NOT NULL
GROUP BY TO_CHAR(collected_at, 'HH24:MI'), collected_at
ORDER BY collected_at DESC
LIMIT #{limit}

SELECT
    time_bucket,
    COALESCE(SUM(total_blk_read_time), 0) as total_blk_read_time,
    COALESCE(SUM(total_blk_write_time), 0) as total_blk_write_time
FROM memory_agg_5m
WHERE instance_id = #{instanceId}
  AND time_bucket >= #{startTime} AND time_bucket  <=  #{endTime}
GROUP BY time_bucket
ORDER BY time_bucket DESC
LIMIT #{limit}
